    get maxToasts() {
        return this._maxToasts;
    }
    set maxToasts(value) {
        this._maxToasts = normalizeNumber(value, {
            fallbackValue: DEFAULT_MAX_TOASTS_SHOWN,
            minValue: 1,
        });
    }
