        let toastIndex = -1;
        let source;
        this._displayToasts = this._displayToasts.filter(({ toastElement, sourceElement }, index) => {
            if (toastElement === closedToast) {
                toastIndex = index;
                source = sourceElement;
                return false;
            }
            return true;
        });
        this.root.removeChild(closedToast);
        this.showNextToast();
        if (!event.detail.isFocused) {
            return;
        }
